import redis

# Connect to Redis cluster
redis_cluster = redis.RedisCluster(
    startup_nodes=[
        {'host': 'redis-node1.example.com', 'port': 6379},
        {'host': 'redis-node2.example.com', 'port': 6379},
        # Add additional Redis nodes as needed
    ],
    password='your_password'
)

# Store sensitive user data in Redis with TTL
def store_user_data(user_id, session_token, api_key):
    redis_cluster.setex(f'user_{user_id}:session_token', 3600, session_token)
    redis_cluster.setex(f'user_{user_id}:api_key', 3600, api_key)

# Retrieve sensitive user data from Redis
def retrieve_user_data(user_id):
    session_token = redis_cluster.get(f'user_{user_id}:session_token')
    api_key = redis_cluster.get(f'user_{user_id}:api_key')
    return session_token, api_key